const input = $input.first().json;
const action = input.action || 'list_events';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

async function getGoogleToken() {
  const creds = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&select=cred_key,cred_value',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  const m = {};
  for (const c of creds) m[c.cred_key] = c.cred_value;
  if (!m.access_token || !m.refresh_token) throw new Error('Google OAuth not configured.');
  if (new Date(m.token_expiry || 0) <= new Date(Date.now() + 5 * 60 * 1000)) {
    const resp = await helpers.httpRequest({
      method: 'POST', url: 'https://oauth2.googleapis.com/token',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'grant_type=refresh_token&refresh_token=' + encodeURIComponent(m.refresh_token) + '&client_id=' + encodeURIComponent(m.client_id) + '&client_secret=' + encodeURIComponent(m.client_secret)
    });
    if (resp.error) throw new Error('Token refresh failed: ' + resp.error_description);
    const newExpiry = new Date(Date.now() + (resp.expires_in - 60) * 1000).toISOString();
    for (const [key, val] of [['access_token', resp.access_token], ['token_expiry', newExpiry]]) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.' + key, headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: key, cred_value: val }) });
    }
    if (resp.refresh_token) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.refresh_token', headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: 'refresh_token', cred_value: resp.refresh_token }) });
    }
    return resp.access_token;
  }
  return m.access_token;
}

let accessToken;
try { accessToken = await getGoogleToken(); } catch(e) { return [{ json: { error: e.message } }]; }

const gHeaders = { 'Authorization': 'Bearer ' + accessToken, 'Content-Type': 'application/json' };
const CAL_BASE = 'https://www.googleapis.com/calendar/v3';

// === list_events ===
if (action === 'list_events') {
  const calId = input.calendar_id || 'primary';
  const maxResults = parseInt(input.max_results) || 10;
  const timeMin = input.time_min || new Date().toISOString();
  let url = CAL_BASE + '/calendars/' + encodeURIComponent(calId) + '/events?maxResults=' + maxResults + '&timeMin=' + encodeURIComponent(timeMin) + '&singleEvents=true&orderBy=startTime';
  if (input.time_max) url += '&timeMax=' + encodeURIComponent(input.time_max);

  try {
    const resp = await helpers.httpRequest({ method: 'GET', url, headers: gHeaders });
    if (!resp.items || resp.items.length === 0) return [{ json: { result: 'No upcoming events found.' } }];

    let result = 'Upcoming events (' + resp.items.length + '):\n\n';
    for (const ev of resp.items) {
      const start = ev.start.dateTime || ev.start.date || '';
      const end = ev.end.dateTime || ev.end.date || '';
      result += '**' + (ev.summary || '(no title)') + '**\n';
      result += 'Start: ' + start + '\n';
      result += 'End: ' + end + '\n';
      result += 'ID: ' + ev.id + '\n';
      if (ev.location) result += 'Location: ' + ev.location + '\n';
      if (ev.description) result += 'Description: ' + ev.description.substring(0, 200) + '\n';
      if (ev.attendees) result += 'Attendees: ' + ev.attendees.map(a => a.email).join(', ') + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'Failed to list events: ' + e.message } }]; }

// === create_event ===
} else if (action === 'create_event') {
  const summary = input.summary;
  const start = input.start;
  const end = input.end;
  if (!summary || !start || !end) return [{ json: { error: 'Parameters "summary", "start" (ISO datetime), and "end" (ISO datetime) are required.' } }];
  const calId = input.calendar_id || 'primary';

  const eventBody = {
    summary,
    start: { dateTime: start, timeZone: 'Europe/Berlin' },
    end: { dateTime: end, timeZone: 'Europe/Berlin' }
  };
  if (input.description) eventBody.description = input.description;
  if (input.location) eventBody.location = input.location;

  try {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: CAL_BASE + '/calendars/' + encodeURIComponent(calId) + '/events',
      headers: gHeaders,
      body: JSON.stringify(eventBody)
    });
    return [{ json: { result: 'Event created: ' + resp.summary + '\nStart: ' + (resp.start.dateTime || resp.start.date) + '\nID: ' + resp.id + '\nLink: ' + (resp.htmlLink || '') } }];
  } catch(e) { return [{ json: { error: 'Failed to create event: ' + e.message } }]; }

// === update_event ===
} else if (action === 'update_event') {
  const eventId = input.event_id;
  if (!eventId) return [{ json: { error: 'Parameter "event_id" is required.' } }];
  const calId = input.calendar_id || 'primary';

  const patchBody = {};
  if (input.summary) patchBody.summary = input.summary;
  if (input.start) patchBody.start = { dateTime: input.start, timeZone: 'Europe/Berlin' };
  if (input.end) patchBody.end = { dateTime: input.end, timeZone: 'Europe/Berlin' };
  if (input.description) patchBody.description = input.description;
  if (input.location) patchBody.location = input.location;

  try {
    const resp = await helpers.httpRequest({
      method: 'PATCH',
      url: CAL_BASE + '/calendars/' + encodeURIComponent(calId) + '/events/' + encodeURIComponent(eventId),
      headers: gHeaders,
      body: JSON.stringify(patchBody)
    });
    return [{ json: { result: 'Event updated: ' + resp.summary + '\nID: ' + resp.id } }];
  } catch(e) { return [{ json: { error: 'Failed to update event: ' + e.message } }]; }

// === delete_event ===
} else if (action === 'delete_event') {
  const eventId = input.event_id;
  if (!eventId) return [{ json: { error: 'Parameter "event_id" is required.' } }];
  const calId = input.calendar_id || 'primary';

  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: CAL_BASE + '/calendars/' + encodeURIComponent(calId) + '/events/' + encodeURIComponent(eventId),
      headers: gHeaders
    });
    return [{ json: { result: 'Event ' + eventId + ' deleted successfully.' } }];
  } catch(e) { return [{ json: { error: 'Failed to delete event: ' + e.message } }]; }

// === list_calendars ===
} else if (action === 'list_calendars') {
  try {
    const resp = await helpers.httpRequest({ method: 'GET', url: CAL_BASE + '/users/me/calendarList', headers: gHeaders });
    if (!resp.items || resp.items.length === 0) return [{ json: { result: 'No calendars found.' } }];

    let result = 'Your Calendars:\n\n';
    for (const cal of resp.items) {
      result += '**' + cal.summary + '**\n';
      result += 'ID: ' + cal.id + '\n';
      result += 'Access: ' + cal.accessRole + '\n';
      if (cal.description) result += 'Description: ' + cal.description + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch(e) { return [{ json: { error: 'Failed to list calendars: ' + e.message } }]; }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: list_events, create_event, update_event, delete_event, list_calendars.' } }];
}
